class.resource:
/*****************************************************************/ /* GENERICO */ /*****************************************************************/ SELECT I.oi_instance, I.c_estructura, T.oi_thread, R.c_rol, OP.oi_organigrama, EP.c_estructura resolverdor, EHP.oi_entidad, EHP.d_entidad_estr FROM WRK02_INSTANCES i, WRK02_THREADS t, WRK01_WF W, WRK01_ROLES_NODE R, WRK05_ORGANIGRAMAS o, WRK05_ORGANIGRAMAS op, WRK05_ESTRUCTURA ep, WRK05_ESTR_ESTR eep, WRK05_ENTIDAD_ESTR ehp WHERE I.oi_wf=W.oi_wf and I.oi_instance=T.oi_instance and W.oi_organigrama=O.oi_organigrama and O.c_organigrama=OP.c_organigrama and O.e_version_pub=OP.e_version and T.oi_node=R.oi_node and OP.oi_organigrama=EP.oi_organigrama and EP.oi_estructura=EEP.oi_estructura and EP.oi_estructura=EHP.oi_estructura and R.c_resolver=1 and R.c_rol=EP.c_role and I.c_estructura=EEP.c_estructura and T.c_asign_rol is null and T.d_asign_etty is null and I.c_estado_ej='R' and T.c_estado='WP' and
oi_entidad='001AA0E914F9-4F3D19C80350-000122A61AA0' oi_thread=4
/*****************************************************************/ /* ROL ASIGNADO */ /*****************************************************************/ select I.oi_instance, I.c_estructura, T.oi_thread, T.c_asign_rol, OP.oi_organigrama, EP.c_estructura resolverdor, EHP.oi_entidad, EHP.d_entidad_estr from wrk02_instances I, wrk02_threads T, wrk01_wf W, wrk05_organigramas O, wrk05_organigramas OP, wrk05_estructura EP, wrk05_estr_estr EEP, wrk05_entidad_estr EHP where I.oi_wf=W.oi_wf and I.oi_instance=T.oi_instance and W.oi_organigrama=O.oi_organigrama and O.c_organigrama=OP.c_organigrama and O.e_version_pub=OP.e_version and OP.oi_organigrama=EP.oi_organigrama and EP.oi_estructura=EEP.oi_estructura and EP.oi_estructura=EHP.oi_estructura and T.c_asign_rol=EP.c_role and I.c_estructura=EEP.c_estructura and T.d_asign_etty is null and I.c_estado_ej='R' and T.c_estado='WP' and
oi_entidad='001AA0E914F9-4F3D19C80350-000122A61AA0' oi_thread=4
/*****************************************************************/ /* ENTIDAD ASIGNADA */ /*****************************************************************/ select I.oi_instance, I.c_estructura, T.oi_thread, T.c_asign_rol from wrk02_instances I, wrk02_threads T where I.oi_instance=T.oi_instance and I.c_estado_ej='R' and T.c_estado='WP' and
d_asign_etty='001AA0E914F9-4F3D19C80350-000122A61AA0'
/*****************************************************************/ /* RESOLVER POR EL OWNER */ /*****************************************************************/ select I.oi_instance, I.c_estructura, T.oi_thread, R.c_rol from wrk02_instances I, wrk02_threads T, wrk01_wf W, wrk01_roles_node R where I.oi_wf=W.oi_wf and I.oi_instance=T.oi_instance and T.oi_node=R.oi_node and R.c_resolver=1 and R.c_rol='OWNER' and T.c_asign_rol is null and T.d_asign_etty is null and I.c_estado_ej='R' and T.c_estado='WP' and I.d_owner='001AA0E914F9-4F3D19C80350-000122A61AA0' oi_thread=4

